def _hash_token(token: str) -> str:
    return hashlib.sha256(token.encode("utf-8")).hexdigest()

# Token store: token_hash -> token data
TOKENS: Dict[str, Dict] = {}

security = HTTPBearer(auto_error=False)

class LoginRequest(BaseModel):
    username: str
    password: str

class TokenResponse(BaseModel):
    access_token: str
    token_type: str = "bearer"
    expires_at: datetime

def _issue_token(username: str) -> TokenResponse:
    raw = secrets.token_urlsafe(32)
    token_hash = _hash_token(raw)
    now = datetime.now(timezone.utc)
    expires_at = now + timedelta(seconds=TOKEN_TTL_SECONDS)
    TOKENS[token_hash] = {
        "username": username,
        "issued_at": now,
        "expires_at": expires_at,
    }
    return TokenResponse(access_token=raw, expires_at=expires_at)

def _validate_token(raw_token: str) -> Dict:
    token_hash = _hash_token(raw_token)
    data = TOKENS.get(token_hash)
    if not data:
        raise HTTPException(status_code=status.HTTP_401_UNAUTHORIZED, detail="Invalid token")
    if datetime.now(timezone.utc) >= data["expires_at"]:
        TOKENS.pop(token_hash, None)
        raise HTTPException(status_code=status.HTTP_401_UNAUTHORIZED, detail="Token expired")
    return data

def get_current_user(creds: Optional[HTTPAuthorizationCredentials] = Depends(security)) -> str:
    if creds is None or not creds.credentials:
        raise HTTPException(status_code=status.HTTP_401_UNAUTHORIZED, detail="Missing token")
    if creds.scheme.lower() != "bearer":
        raise HTTPException(status_code=status.HTTP_401_UNAUTHORIZED, detail="Invalid auth scheme")
    data = _validate_token(creds.credentials)
    return data["username"]

@app.post("/login", response_model=TokenResponse)
def login(payload: LoginRequest):
    expected = USERS.get(payload.username)
    if expected is None or expected != payload.password:
        raise HTTPException(status_code=status.HTTP_401_UNAUTHORIZED, detail="Invalid credentials")
    return _issue_token(payload.username)

@app.post("/logout")
def logout(creds: Optional[HTTPAuthorizationCredentials] = Depends(security)):
    if creds is None or not creds.credentials:
        raise HTTPException(status_code=status.HTTP_401_UNAUTHORIZED, detail="Missing token")
    token_hash = _hash_token(creds.credentials)
    existed = token_hash in TOKENS
    TOKENS.pop(token_hash, None)
    return {"revoked": existed}

